552	715	listening_tests	5aaa34d2-c34c-4c63-ba02-057f722e791f	{"id":"5aaa34d2-c34c-4c63-ba02-057f722e791f","title":"Using a Coffee Machine","slug":"using-a-coffee-machine","description":"A cross-section or external diagram of a home coffee machine.","accent":"British","duration_seconds":null,"question_count":4,"is_free":true,"instruction_text":"Label the diagram below. Write the correct letter, A-D, next to Questions 1-4.","transcript":"Hello and welcome to your new coffee machine. Let me explain how to use it. First, look at the back of the machine. At the top, on the right side, you will find the water tank. Fill this with cold water. Next, look at the top left of the machine. This is the coffee bean hopper. Pour your fresh beans in here. Then, the machine will grind them for you. Now, in the centre, behind the main door, is the brewing chamber. This is where the hot water mixes with the coffee. You need to clean this part every week. Finally, look at the base of the machine, underneath the cups. This is the drip tray. It catches any spilled coffee, so remember to empty it regularly. Enjoy your coffee!","prosody_script":null,"date_created":"2026-06-11T14:14:23.105Z","date_updated":"2026-06-11T14:14:23.105Z","status":"published","metadata":{"schema_version":"visual_labelling_listening_v1","topic":"Coffee Machine","speaker_role":"Instructor","image_generation_prompt":"A clean, simple technical line drawing of a home coffee machine on a white background. The drawing shows the main door in the centre and some cups resting at the bottom centre. There are four neutral, unlabelled shapes or areas pointed to by clear letter labels A, B, C, and D. Label A points to a container on the top left. Label B points to an internal area in the centre, behind the main door. Label C points to a tall container on the back right. Label D points to a shallow tray area at the base, underneath the cups. Do not print correct answer names on the image. Do not reveal answer locations through icons, coffee beans, water drops, or semantic visual clues. Question-target locations must be visually neutral.","difficulty_notes":{"word_count":131,"visible_label_count":4,"question_count":4,"distractor_label_count":0,"why_this_level":"Meets A2 criteria: ~130 words, 4 questions, 4 labels (A-D), 0 distractors, simple location directions.","distractors":[],"key_phrases":["at the back","at the top","on the right side","top left","in the centre","behind","at the base","underneath"],"visual_fairness_check":{"can_learners_guess_answers_from_image_alone":false,"anti_leak_checked":true,"notes":"No visual clues are given for the tank, hopper, chamber, or tray, only simple shapes and letter labels."}}},"questions_public_json":{"groups":[{"id":"g1","type":"diagram_labelling","title":"Questions 1-4","instruction":"Label the diagram below. Write the correct letter, A-D, next to Questions 1-4.","question_range":{"from":1,"to":4},"media":{"image":{"type":"image","field":"image_file"},"audio":{"type":"audio","field":"audio_file"}},"options":{"type":"letters","values":["A","B","C","D"]},"questions":[{"id":"q1","number":1,"text":"Water tank","input_type":"text","score":1},{"id":"q2","number":2,"text":"Coffee bean hopper","input_type":"text","score":1},{"id":"q3","number":3,"text":"Brewing chamber","input_type":"text","score":1},{"id":"q4","number":4,"text":"Drip tray","input_type":"text","score":1}]}]},"questions_answer_json":[{"id":"q1","correct_answer":"C","acceptable_answers":["C","c"],"score":1,"explanation":"The water tank is located at the back of the machine, at the top on the right side.","transcript_evidence":"First, look at the back of the machine. At the top, on the right side, you will find the water tank."},{"id":"q2","correct_answer":"A","acceptable_answers":["A","a"],"score":1,"explanation":"The coffee bean hopper is located at the top left of the machine.","transcript_evidence":"Next, look at the top left of the machine. This is the coffee bean hopper."},{"id":"q3","correct_answer":"B","acceptable_answers":["B","b"],"score":1,"explanation":"The brewing chamber is in the centre, behind the main door.","transcript_evidence":"Now, in the centre, behind the main door, is the brewing chamber."},{"id":"q4","correct_answer":"D","acceptable_answers":["D","d"],"score":1,"explanation":"The drip tray is located at the base of the machine, underneath the cups.","transcript_evidence":"Finally, look at the base of the machine, underneath the cups. This is the drip tray."}],"thumbnail":null,"map_image":"ee4e7440-3d4e-449b-89c5-5a8be31c20f0","type":"diagram_labelling","topic":null,"tests_taken":"0","level":"basic","audio_file":[8]}	{"level":"basic"}	\N	\N
