738	985	listening_tests	ab5c957c-bdd2-4098-b900-7eedfbd56fe3	{"status":"draft","title":"Swimming Centre Outdoor Area","slug":"swimming-centre-outdoor-area","description":"A top-down map of the outdoor area of a swimming centre. The main entrance is at the bottom centre. A central path runs from the entrance northward through the area. A large outdoor pool is in the centre of the map. There are four neutral areas labelled A, B, C, and D. Area A is in the top left corner, beyond the pool. Area B is to the right of the central path near the entrance. Area C is at the top right, beyond the pool. Area D is to the left of the central path near the entrance.","type":"map_labelling","level":"A2","accent":"British English","duration_seconds":null,"question_count":4,"is_free":true,"instruction_text":"Label the map below. Write the correct letter, A-D, next to Questions 1-4.","transcript":"Welcome to the outdoor area of the swimming centre. I will tell you about the main facilities. When you come in through the entrance, you can see the large outdoor pool straight ahead of you. On your left, just next to the entrance, is our reception. You can buy tickets and get information there. On your right, also near the entrance, are the changing rooms. Please use these before you go to the pool. After your swim, if you are hungry or thirsty, walk along the path and go past the pool. At the top left of the area, you will find our seating area. This is a great place to relax. If you would like something to eat or drink, our refreshment kiosk is at the top right of the area, on the other side of the pool. We hope you enjoy your visit.","prosody_script":null,"questions_public_json":{"groups":[{"id":"g1","type":"map_labelling","title":"Questions 1-4","instruction":"Label the map below. Write the correct letter, A-D, next to Questions 1-4.","question_range":{"from":1,"to":4},"media":{"image":{"type":"image","field":"image_file"},"audio":{"type":"audio","field":"audio_file"}},"options":{"type":"letters","values":["A","B","C","D"]},"questions":[{"id":"q1","number":1,"text":"Reception","input_type":"select","score":1},{"id":"q2","number":2,"text":"Changing rooms","input_type":"select","score":1},{"id":"q3","number":3,"text":"Seating area","input_type":"select","score":1},{"id":"q4","number":4,"text":"Refreshment kiosk","input_type":"select","score":1}]}]},"questions_answer_json":[{"id":"q1","correct_answer":"D","acceptable_answers":["D"],"score":1,"explanation":"The reception is on the left side near the entrance, which corresponds to label D on the map.","transcript_evidence":"On your left, just next to the entrance, is our reception."},{"id":"q2","correct_answer":"B","acceptable_answers":["B"],"score":1,"explanation":"The changing rooms are on the right side near the entrance, which corresponds to label B on the map.","transcript_evidence":"On your right, also near the entrance, are the changing rooms."},{"id":"q3","correct_answer":"A","acceptable_answers":["A"],"score":1,"explanation":"The seating area is at the top left of the outdoor area, beyond the pool, which corresponds to label A on the map.","transcript_evidence":"At the top left of the area, you will find our seating area."},{"id":"q4","correct_answer":"C","acceptable_answers":["C"],"score":1,"explanation":"The refreshment kiosk is at the top right of the outdoor area, on the other side of the pool, which corresponds to label C on the map.","transcript_evidence":"Our refreshment kiosk is at the top right of the area, on the other side of the pool."}],"metadata":{"schema_version":"visual_labelling_listening_v1","topic":"Swimming Centre Outdoor Area","speaker_role":"Swimming centre staff member giving a guided introduction to visitors","image_generation_prompt":"Create a clean, top-down outdoor map of a swimming centre. The map is rectangular. The main entrance is labelled 'Entrance' at the bottom centre. A straight central path runs from the entrance northward to the top of the map. A large rec